# Category: serverless_security

import json
import boto3
import logging
from PIL import Image
from io import BytesIO

# Setup logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize clients
s3 = boto3.client('s3')
sns = boto3.client('sns')

# Define the SNS topic ARN
SNS_TOPIC_ARN = 'arn:aws:sns:us-east-1:123456789012:YourSNSTopic'

def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))
    
    for record in event['Records']:
        bucket = record['s3']['bucket']['name']
        key = record['s3']['object']['key']
        
        try:
            # Read image from S3
            response = s3.get_object(Bucket=bucket, Key=key)
            img_bytes = response['Body'].read()
            
            # Process image (example: convert to thumbnail)
            img = Image.open(BytesIO(img_bytes))
            img.thumbnail((100, 100))
            
            # Save processed image back to S3
            output_key = f'processed/{key}'
            buffer = BytesIO()
            img.save(buffer, format="JPEG")
            buffer.seek(0)
            s3.put_object(Bucket=bucket, Key=output_key, Body=buffer, ContentType='image/jpeg')
            
            # Send notification via SNS
            sns.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=f'Processed image saved to {output_key}'
            )
            
            logger.info(f'Successfully processed and uploaded image to {output_key}')

        except Exception as e:
            logger.error(f'Error processing object {key} from bucket {bucket}: {str(e)}')
            raise e

